def get_cached_by_id(id) do
  key = "id:#{id}"

  ap_id =
    @cachex.fetch!(:user_cache, key, fn _ ->
      user = get_by_id(id)

      if user do
        @cachex.put(:user_cache, "ap_id:#{user.ap_id}", user)
        {:commit, user.ap_id}
      else
        {:ignore, ""}
      end
    end)

  get_cached_by_ap_id(ap_id)
end

