def process(data, url) do
  [:rich_media, :ttl_setters]
  |> Pleroma.Config.get()
  |> Enum.reduce_while({:ok, nil}, fn module, acc ->
    case module.ttl(data, url) do
      ttl when is_number(ttl) -> {:halt, {:ok, ttl}}
      _ -> {:cont, acc}
    end
  end)
end

def find_working_url(domain) do
  [domain_without_path | rest] = split_domain(domain)

  [domain_without_path, "www.#{domain_without_path}"]
  |> Enum.reduce_while({:error, :domain_not_found}, fn d, _acc ->
    case dns_lookup(d) do
      :ok -> {:halt, {:ok, "https://" <> unsplit_domain(d, rest)}}
      {:error, :no_a_record} -> {:cont, {:error, :domain_not_found}}
    end
  end)
end

